  \textbf{\large Verifica di Inglese: British vs American English} \\
  \vspace{0.3cm}
  \small \textbf{Nome:} \underline{\hspace{6cm}} \quad \textbf{Classe e Data:} \underline{\hspace{4cm}} \\
